const loopItem = $input.first().json;
const xmlString = $input.item.json.data || '';

if (xmlString.includes('<PubmedArticleSet>')) {
  // EFetch case - parse articles
  // ... existing article parsing code
} else {
  // ESearch case - parse Count & IdList
  const countMatch = xmlString.match(/<Count>(\d+)<\/Count>/);
  const count = parseInt(countMatch?.[1] || '0');

  const pmidRegex = /<Id>(\d+)<\/Id>/g;
  const pmids = [];
  let match;
  while ((match = pmidRegex.exec(xmlString)) !== null) {
    pmids.push(match[1]);
  }

  return [{
    json: {
      ...loopItem,
      pubmed_count: count,
      pubmed_pmids: pmids.slice(0, 500),
      needs_fetch: count > 0,
      studies_found: count > 0,
      fetched_at: new Date().toISOString()
    }
  }];
}

// n8n Code node (Run Once for All Items)

// 1) Find the context item (gap_scores / association metadata)
let context = null;

for (const item of $input.all()) {
  const j = item.json || {};
  if (
    j.association_id !== undefined ||
    j.herb_id !== undefined ||
    j.disease_id !== undefined ||
    j.botanical_name !== undefined
  ) {
    context = j;
    break;
  }
}

// Fallback to first item if nothing matched (keeps workflow from crashing)
if (!context) {
  context = $input.first().json || {};
}

// 2) Find the EFetch XML item
let xmlString = '';
for (const item of $input.all()) {
  const j = item.json || {};
  if (typeof j.data === 'string' && j.data.includes('<PubmedArticleSet>')) {
    xmlString = j.data;
    break;
  }
}

if (!xmlString) {
  return [{ json: { error: 'No EFetch XML found', ...context } }];
}

// 3) Parse PubMed articles
const papers = [];
const articleRegex = /<PubmedArticle>.*?<\/PubmedArticle>/gs;
const articles = xmlString.match(articleRegex) || [];

for (const article of articles) {
  const pmidMatch = article.match(/<PMID[^>]*>(\d+)<\/PMID>/);
  const titleMatch = article.match(/<ArticleTitle>(.*?)<\/ArticleTitle>/s);

  const abstractMatches =
    article.match(/<AbstractText[^>]*>(.*?)<\/AbstractText>/gs) || [];
  const abstractText = abstractMatches
    .map(m => m.replace(/<[^>]*>/g, '').trim())
    .join(' ')
    .substring(0, 2000);

  const journalMatch = article.match(/<MedlineTA>(.*?)<\/MedlineTA>/);
  const yearMatch = article.match(/<Year>(\d{4})<\/Year>/);

  if (pmidMatch && titleMatch) {
    papers.push({
      pmid: parseInt(pmidMatch[1], 10),
      title: titleMatch[1].replace(/<[^>]*>/g, '').trim().substring(0, 500),
      abstract: abstractText,
      journal: journalMatch ? journalMatch[1].trim().substring(0, 200) : 'Unknown',
      publication_date: yearMatch ? yearMatch[1] : 'unknown',

      // Propagate context reliably (may be null/undefined if upstream truly didn't provide)
      association_id: context.association_id ?? null,
      herb_id: context.herb_id ?? null,
      disease_id: context.disease_id ?? null,
      botanical_name: context.botanical_name ?? null,

      fetched_at: new Date().toISOString(),
    });
  }
}

return papers.map(paper => ({ json: paper }));

// Sanitize: Process ALL items (Run Once for All Items mode)
const items = $input.all().map(item => {
  const data = item.json;
  const escapeSql = (str) => str ? String(str)
    .replace(/'/g, "''")
    .replace(/\n/g, ' ')
    .replace(/\r/g, ' ')
    .replace(/\t/g, ' ')
    .trim() : '';

  return {
    json: {
      ...data,
      title_safe: escapeSql(data.title),
      abstract_safe: escapeSql(data.abstract),
      journal_safe: escapeSql(data.journal)
    }
  };
});

return items;

// Preserve ALL data for downstream If + studies
const item = $input.item.json;
const categoryName = item.diseasecategory || item.category_name;  // From assoc or prior
const output = {
  ...item,
  category_id: [/* Query: SELECT category_id FROM therapeutic_categories WHERE category_name = categoryName */],  // Resolve via DB or prior node
  pubmed_searches: item.pubmed_count || 0,
  last_pubmed_check: item.fetched_at,
  needs_fetch: (item.pubmed_count || 0) > 0
};
return [{ json: output }];

// Safe SQL builder
const item = $input.item.json;
const count = item.pubmed_count || 0;
const status = count > 0 ? 'found_results' : (count === 0 ? 'no_results' : 'search_failed');
const safeBotanical = (item.botanical_name || '').replace(/['"]/g, '').replace(/\s+/g, ' ');  // Strip quotes/spaces
const safeDisease = (item.disease_english || '').replace(/['"]/g, '').replace(/\s+/g, ' ');
const notes = `PubMed eSearch: Count=${count} (${safeBotanical} ${safeDisease})`;

return [{
  json: {
    ...item,
    sql_status: status,
    sql_notes: notes,
    sql_count: 1  // Fixed increment
  }
}];
